body:
This PR adds a memory initialization flag allowing `readmem` statements to be generated outside the `ifndef SYNTHESIS` block allowing synthesis tools (like Yosys) to pick-it-up.

The flag defaults to `false` keeping the current behavior:

```systemverilog
// Generated by CIRCT unknown git version
// VCS coverage exclude_file
module mem_combMem_0(
  input  [10:0] R0_addr,
  input         R0_en,
                R0_clk,
  input  [10:0] W0_addr,
  input         W0_en,
                W0_clk,
  input  [31:0] W0_data,
  output [31:0] R0_data
);

  reg [31:0] Memory[0:2047];
  reg        _GEN;
  reg [10:0] _GEN_0;
  always @(posedge R0_clk) begin
    _GEN <= R0_en;
    _GEN_0 <= R0_addr;
  end // always @(posedge)
  always @(posedge W0_clk) begin
    if (W0_en)
      Memory[W0_addr] <= W0_data;
  end // always @(posedge)
  `ifndef SYNTHESIS
    initial
      $readmemh("progload-RAM.mem", Memory);
  `endif // not def SYNTHESIS
  assign R0_data = _GEN ? Memory[_GEN_0] : 32'bx;
endmodule

```

With the flag:

```systemverilog
// Generated by CIRCT unknown git version
// VCS coverage exclude_file
module mem_combMem_0(
  input  [10:0] R0_addr,
  input         R0_en,
                R0_clk,
  input  [10:0] W0_addr,
  input         W0_en,
                W0_clk,
  input  [31:0] W0_data,
  output [31:0] R0_data
);

  reg [31:0] Memory[0:2047];
  reg        _GEN;
  reg [10:0] _GEN_0;
  always @(posedge R0_clk) begin
    _GEN <= R0_en;
    _GEN_0 <= R0_addr;
  end // always @(posedge)
  always @(posedge W0_clk) begin
    if (W0_en)
      Memory[W0_addr] <= W0_data;
  end // always @(posedge)
  initial
    $readmemh("progload-RAM.mem", Memory);
  assign R0_data = _GEN ? Memory[_GEN_0] : 32'bx;
endmodule
```

Fixes #4752.
